using Xunit; using Moq; using SkyCD.vNext.SDK; using SkyCD.vNext.SDK.Capabilities; using System.Collections.Generic; using System.Threading.Tasks; namespace SkyCD.Plugin.WebBrowser.Tests { public class WebBrowserPluginTests { private readonly WebBrowserPlugin _plugin; private readonly Mock<IPluginHost> _mockHost; public WebBrowserPluginTests() { _plugin = new WebBrowserPlugin(); _mockHost = new Mock<IPluginHost>(); _mockHost.Setup(h => h.GetPluginSettingsAsync()).ReturnsAsync(new Dictionary<string, object>()); } [Fact] public async Task ExecuteMenuCommandAsync_UsesContextUrlFirst() { var mockContext = new Mock<IMenuCommandContext>(); mockContext.Setup(c => c.Properties).Returns(new Dictionary<string, object> { { "url", "https://example.com" } }); await _plugin.ExecuteMenuCommandAsync(mockContext.Object); _mockHost.Verify(h => h.LaunchExternalUrlAsync("https://example.com"), Times.Once); } [Fact] public async Task ExecuteMenuCommandAsync_UsesConfigUrlWhenNoContextUrl() { _mockHost.Setup(h => h.GetPluginSettingsAsync()).ReturnsAsync(new Dictionary<string, object> { { "defaultUrl", "https://config.example.com" } }); var mockContext = new Mock<IMenuCommandContext>(); mockContext.Setup(c => c.Properties).Returns(new Dictionary<string, object>()); await _plugin.ExecuteMenuCommandAsync(mockContext.Object); _mockHost.Verify(h => h.LaunchExternalUrlAsync("https://config.example.com"), Times.Once); } [Fact] public async Task ExecuteMenuCommandAsync_FallsBackToAboutBlankWhenNoUrls() { var mockContext = new Mock<IMenuCommandContext>(); mockContext.Setup(c => c.Properties).Returns(new Dictionary<string, object>()); await _plugin.ExecuteMenuCommandAsync(mockContext.Object); _mockHost.Verify(h => h.LaunchExternalUrlAsync("about:blank"), Times.Once); } [Fact] public async Task IsValidUrlScheme_RejectsInvalidSchemes() { var result = _plugin.IsValidUrlScheme("ftp://example.com"); Assert.False(result); } [Fact] public async Task IsValidUrlScheme_AcceptsAllowedSchemes() { Assert.True(_plugin.IsValidUrlScheme("http://example.com")); Assert.True(_plugin.IsValidUrlScheme("https://example.com")); Assert.True(_plugin.IsValidUrlScheme("about:blank")); } } }